                    new VariantDef("Primary", "Primary", 0, "0", new FieldDef[]
                    { }),
                    new VariantDef("Secondary", "Secondary", 1, "1", new FieldDef[]
                    { }),
                }),
                ["ObjectPlayerIndex"] = new EnumDef("ObjectPlayerIndex", 1, new VariantDef[]
                {
                    new VariantDef("PlayerIndex", "PlayerIndex", 0, "0", new FieldDef[]
                    {
                        new FieldDef("Object.Player", "Ref0:Gametype/base/mpvr/megl/MegaloVars/ObjectVars/objectplayers", 2),
                    }),
                    new VariantDef("None", "None", 1, "1", new FieldDef[]
                    { }),
                }),
                ["StringToken"] = new EnumDef("StringToken", 3, new VariantDef[]
                {
                    new VariantDef("None", "None", 0, "000", new FieldDef[]
                    { }),
                    new VariantDef("PlayerVar", "PlayerVar", 1, "001", new FieldDef[]
                    {
                        new FieldDef("PlayerType", "Enumref:PlayerTypeRef", 0),
                    }),
                    new VariantDef("TeamVar", "TeamVar", 2, "010", new FieldDef[]
                    {
                        new FieldDef("TeamType", "Enumref:TeamTypeRef", 0),
                    }),
                    new VariantDef("ObjectVar", "ObjectVar", 3, "011", new FieldDef[]
                    {
                        new FieldDef("ObjectType", "Enumref:ObjectTypeRef", 0),
                    }),
                    new VariantDef("NumericVar", "NumericVar", 4, "100", new FieldDef[]
                    {
                        new FieldDef("NumberType", "Enumref:NumericTypeRef", 0),
                    }),
                    new VariantDef("TimerVar", "TimerVar", 5, "101", new FieldDef[]
                    {
                        new FieldDef("TimerType", "Enumref:TimerTypeRef", 0),
                    }),
                    new VariantDef("TimerVarAswell", "TimerVarAswell", 6, "110", new FieldDef[]
                    {
