                    new VariantDef("Unlabelled·", "Unlabelled·", 7, "111", new FieldDef[]
                    { }),
                }),
                ["StringVars2"] = new EnumDef("StringVars2", 2, new VariantDef[]
                {
                    new VariantDef("None", "None", 0, "00", new FieldDef[]
                    { }),
                    new VariantDef("Vars1", "Vars1", 1, "01", new FieldDef[]
                    {
                        new FieldDef("Token", "Enumref:StringToken", 0),
                    }),
                    new VariantDef("Vars2", "Vars2", 2, "10", new FieldDef[]
                    {
